-- ============================================================
-- Dev-only staff logins (admin / employee / kitchen)
--
-- These passwords are checked into the repo on purpose — they only work
-- against the local Supabase started by `npx supabase start`. For production,
-- create users through Supabase Studio or the admin API and set the role via
-- `app_metadata` (never `user_metadata`).
-- ============================================================
do $$
declare
  v_users jsonb := jsonb_build_array(
    jsonb_build_object('id','aaaaaaaa-0000-0000-0000-000000000001','email','admin@dineflow.local',   'role','admin',    'password','admin123'),
    jsonb_build_object('id','aaaaaaaa-0000-0000-0000-000000000002','email','employee@dineflow.local','role','employee', 'password','employee123'),
    jsonb_build_object('id','aaaaaaaa-0000-0000-0000-000000000003','email','kitchen@dineflow.local', 'role','kitchen',  'password','kitchen123')
  );
  v_u jsonb;
  v_id uuid;
begin
  for v_u in select * from jsonb_array_elements(v_users)
  loop
    v_id := (v_u->>'id')::uuid;

    insert into auth.users (
      instance_id, id, aud, role, email, encrypted_password,
      email_confirmed_at, raw_app_meta_data, raw_user_meta_data,
      created_at, updated_at, confirmation_token, recovery_token, email_change_token_new, email_change
    )
    values (
      '00000000-0000-0000-0000-000000000000',
      v_id,
      'authenticated',
      'authenticated',
      v_u->>'email',
      crypt(v_u->>'password', gen_salt('bf')),
      now(),
      jsonb_build_object('provider','email','providers',jsonb_build_array('email'),'role', v_u->>'role'),
      '{}'::jsonb,
      now(), now(),
      '', '', '', ''
    )
    on conflict (id) do update set
      encrypted_password = excluded.encrypted_password,
      raw_app_meta_data  = excluded.raw_app_meta_data;

    insert into auth.identities (
      provider_id, user_id, identity_data, provider, last_sign_in_at, created_at, updated_at
    )
    values (
      v_u->>'email', v_id,
      jsonb_build_object('sub', v_id::text, 'email', v_u->>'email', 'email_verified', true),
      'email', now(), now(), now()
    )
    on conflict (provider, provider_id) do nothing;
  end loop;
end $$;
